        $.post('panel/electionvoting/electionvoting_main.php', {
            code: code
        }, (data) => {
            if(data.trim() == 'Close'){
                modal_alert('Election Voting is currently unavaliable.', 'danger', 5000)
                to_dashboard();
            } else if(data.trim() == 'You already voted for this election.'){
                modal_alert('You already voted for this election.', 'danger', 5000)
                to_dashboard();
            } else if(data.trim() == 'Error code: 8002'){
                modal_alert('Invalid code.', 'danger', 5000)
                to_dashboard();
            } else if(data.trim() == 'Error code: 8001'){
                modal_alert('Unkown Error', 'danger', 5000)
                to_dashboard();
            } else if(data.trim() == 'Error code: 8000'){
                modal_alert('Your current data does not match with the voting election settings', 'danger', 5000)
