        $.post('panel/admission/actions/check_admission_status.php', {
            studid: '20191124'
        }, (data) => {
            if (data.trim().split("~~")[0] == 'success') {
                modal_confirm("isAcceptedTerms("+data.trim().split("~~")[1]+")", "", data.trim().split("~~")[2])
            } else {
                modal_alert(data, 'danger', 8000)
            }
        })
    };

    function isAcceptedTerms(a) {
        if (a == 0) {
            var counter = 5;
            $('#mdladmission_termsandconditions').modal('show');
            $('#btnadd_accepttheterms').text('Accept the terms (' + counter + ')');
            btnclearinterval = setInterval(function() {
                counter--;
                $('#btnadd_accepttheterms').text('Accept the terms (' + counter + ')');
                if (counter == 0) {
                    clearInterval(btnclearinterval);
                    $('#btnadd_accepttheterms').text('Accept the terms');
                    $('#btnadd_accepttheterms').prop('disabled', false);
                }
            }, 1000);

        } else {
            submitOldStudentAdmission();
        }
    }

    function submitOldStudentAdmission(){
        $.post('panel/admission/actions/submit_oldstud_admission.php', {
            studid: '20191124'
        }, (data) => {
            if (data == 'success') {
                $('#mdladmission_termsandconditions').modal('hide');
                setTimeout(() => {
                    $('#mdladmission_success').modal('show');
                }, 500);
            } else {
                modal_alert(data, 'danger', 8000)
            }
        })
    }
