<!-- Modal Submit Success -->
<div class="modal fade" id="mdlvotinginputcode" data-bs-backdrop="static" data-bs-keyboard="false" tabindex="-1" aria-labelledby="staticBackdropLabel" aria-hidden="true">
    <div class="modal-dialog">
        <div class="modal-content">
            <div class="modal-header py-2">
                <h6 class="header-title">Enter Voting Code</h6>
                <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close"></button>
            </div>
            <div class="modal-body px-3 py-2">
                <form id="frmvotingcode" autocomplete="off">
                    <input id="invotingcode" class="form-control form-control-sm" type="text" required="">
                </form>
            </div>
            <div class="modal-footer py-2">
                <button id="btnsubmitvotingcode" type="submit" form="frmvotingcode" class="btn btn-sm btn-primary px-4 rounded-3 w-100">Submit</button>
            </div>
        </div>
    </div>
</div>
<script>
     $(document).ready(function () {
        $('#frmvotingcode').submit(function (e) { 
            e.preventDefault();
            checkelectionvoting()
        });
    });
    
    const checkelectionvoting = () => {
        btnDisable('#btnsubmitvotingcode',true)
        $('#btnsubmitvotingcode').html('<div class="spinner-border spinner-border-sm" role="status"></div>');
        $.post('panel/electionvoting/actions/check_voting_code.php', {
            code: $('#invotingcode').val(),
        }, (data) => {
            btnDisable('#btnsubmitvotingcode',false)
            $('#btnsubmitvotingcode').html('Submit')
            if (data.trim() == 'success') {
                to_electionvotingportal($('#invotingcode').val());
            } else if(data.trim() == 'invalid'){
                modal_alert('Invalid code. Please try again.', 'danger', 8000)
            } else if(data.trim() == 'Close'){
                modal_alert('Voting is currently unavaliable', 'danger', 8000)
            } else {
                modal_alert(data.trim(), 'danger', 8000)
            }
        })
    };
</script>
